   1→/**
   2→ * Conversation Fork Feature
   3→ *
   4→ * Allows users to fork/branch a conversation at any user message.
   5→ * When forking, the conversation up to that point is exported as markdown
   6→ * and pasted into a new Gemini conversation. Both conversations are linked
   7→ * via fork indicators for easy navigation between branches.
   8→ */
   9→import browser from 'webextension-polyfill';
  10→
  11→import { StorageKeys } from '@/core/types/common';
  12→import { isExtensionContextInvalidatedError } from '@/core/utils/extensionContext';
