  15→import { getTranslationSync } from '../../../utils/i18n';
  16→import { ForkNodesService } from './ForkNodesService';
  17→import { buildBranchDisplayNodes, resolveForkPlan } from './branching';
  18→import { collectForkChatPairs } from './chatPairs';
  19→import { composeForkInputWithContext } from './forkContext';
  20→import type { ForkNode } from './forkTypes';
  21→import { type ForkExtractedTurn, buildForkMarkdown } from './markdown';
  22→import { makeStableTurnId, normalizeTurnId } from './turnId';
  23→
