 267→// ============================================================================
 268→// Helpers
 269→// ============================================================================
 270→
 271→function extractConversationIdFromUrl(): string | null {
 272→  const appMatch = window.location.pathname.match(/\/app\/([^/?#]+)/);
 273→  if (appMatch?.[1]) return appMatch[1];
 274→  const gemMatch = window.location.pathname.match(/\/gem\/[^/]+\/([^/?#]+)/);
 275→  return gemMatch?.[1] || null;
 276→}
 277→
 278→function getConversationTitle(): string {
 279→  const conversationId = extractConversationIdFromUrl();
 280→  if (conversationId) {
 281→    const escapedId = conversationId.replace(/"/g, '\\"');
 282→    const link = document.querySelector<HTMLAnchorElement>(
 283→      `[data-test-id="conversation"][jslog*="c_${escapedId}"] a, a[href*="/app/${escapedId}"]`,
 284→    );
 285→    if (link?.textContent?.trim()) return link.textContent.trim();
 286→  }
 287→  return document.title || 'Untitled';
 288→}
 289→
 290→function ensureTurnId(el: HTMLElement, index: number): string {
 291→  const stableId = makeStableTurnId(index);
 292→  const current = el.dataset?.turnId || '';
 293→  if (normalizeTurnId(current) !== stableId) {
 294→    el.dataset.turnId = stableId;
 295→  }
 296→  return stableId;
 297→}
 298→
 299→function resolveUserMessageHost(userEl: HTMLElement): HTMLElement {
 300→  const preferred =
 301→    userEl.querySelector<HTMLElement>('.user-query-bubble-with-background') ||
 302→    userEl.querySelector<HTMLElement>('user-query-content .user-query-bubble-with-background') ||
 303→    userEl.querySelector<HTMLElement>('.user-query-bubble-container');
 304→  return preferred || userEl;
 305→}
 306→
 307→function findUserCopyButtonAnchor(userEl: HTMLElement): HTMLElement | null {
 308→  const copyButton =
 309→    userEl.querySelector<HTMLElement>('button[data-test-id="copy-button"]') ||
 310→    userEl
 311→      .querySelector<HTMLElement>(
 312→        'button mat-icon[fonticon="content_copy"], button mat-icon[data-mat-icon-name="content_copy"]',
 313→      )
 314→      ?.closest<HTMLElement>('button');
 315→
 316→  if (!copyButton) return null;
 317→  return copyButton.parentElement || copyButton;
 318→}
 319→
 320→function resolveForkButtonHost(userEl: HTMLElement): HTMLElement {
 321→  return findUserCopyButtonAnchor(userEl) || resolveUserMessageHost(userEl);
 322→}
 323→
 324→function extractConversationIdFromHref(href: string): string | null {
 325→  try {
 326→    const url = new URL(href, window.location.origin);
 327→    const appMatch = url.pathname.match(/\/app\/([^/?#]+)/);
 328→    if (appMatch?.[1]) return appMatch[1];
 329→    const gemMatch = url.pathname.match(/\/gem\/[^/]+\/([^/?#]+)/);
 330→    return gemMatch?.[1] || null;
 331→  } catch {
 332→    return null;
 333→  }
 334→}
 335→
 336→function findSidebarConversationLinkById(conversationId: string): HTMLAnchorElement | null {
 337→  const links = Array.from(
 338→    document.querySelectorAll<HTMLAnchorElement>('a[href*="/app/"], a[href*="/gem/"]'),
 339→  );
 340→  for (const link of links) {
 341→    if (extractConversationIdFromHref(link.href) === conversationId) return link;
 342→  }
 343→  return null;
 344→}
 345→
 346→function triggerNativeClick(target: HTMLElement): void {
 347→  const options = { bubbles: true, cancelable: true, view: window };
 348→  target.dispatchEvent(new MouseEvent('pointerdown', options));
 349→  target.dispatchEvent(new MouseEvent('mousedown', options));
 350→  target.dispatchEvent(new MouseEvent('mouseup', options));
 351→  target.dispatchEvent(new MouseEvent('click', options));
 352→}
 353→
 354→function navigateToForkConversation(node: ForkNode): void {
 355→  if (!node.conversationId) return;
 356→  const currentConversationId = extractConversationIdFromUrl();
 357→  if (currentConversationId === node.conversationId) return;
 358→
 359→  const sidebarLink = findSidebarConversationLinkById(node.conversationId);
 360→  if (sidebarLink) {
 361→    triggerNativeClick(sidebarLink);
 362→    return;
 363→  }
 364→
 365→  const fallbackUrl =
 366→    node.conversationUrl ||
 367→    `${window.location.origin}/app/${encodeURIComponent(node.conversationId)}`;
 368→  window.location.assign(fallbackUrl);
 369→}
 370→
 371→function collectSidebarConversationIds(): Set<string> {
 372→  const ids = new Set<string>();
 373→  const links = document.querySelectorAll<HTMLAnchorElement>('a[href*="/app/"], a[href*="/gem/"]');
 374→  links.forEach((link) => {
 375→    const id = extractConversationIdFromHref(link.href);
 376→    if (id) ids.add(id);
 377→  });
 378→  return ids;
 379→}
 380→
 381→async function getPreferredLanguage(): Promise<string | undefined> {
 382→  try {
 383→    const syncResult = await browser.storage.sync.get(StorageKeys.LANGUAGE);
 384→    const syncLanguage = syncResult?.[StorageKeys.LANGUAGE];
 385→    if (typeof syncLanguage === 'string' && syncLanguage.trim()) return syncLanguage;
 386→  } catch {
 387→    // Ignore sync storage failures.
 388→  }
 389→
 390→  try {
 391→    const localResult = await browser.storage.local.get(StorageKeys.LANGUAGE);
 392→    const localLanguage = localResult?.[StorageKeys.LANGUAGE];
 393→    if (typeof localLanguage === 'string' && localLanguage.trim()) return localLanguage;
 394→  } catch {
 395→    // Ignore local storage failures.
 396→  }
 397→
 398→  return undefined;
 399→}
 400→
 401→async function checkConversationExists(
 402→  node: ForkNode,
 403→  sidebarConversationIds: Set<string>,
 404→): Promise<boolean> {
 405→  const currentConversationId = extractConversationIdFromUrl();
 406→  if (currentConversationId && node.conversationId === currentConversationId) return true;
 407→  if (sidebarConversationIds.has(node.conversationId)) {
 408→    conversationExistenceCache.set(node.conversationId, { exists: true, checkedAt: Date.now() });
 409→    return true;
 410→  }
 411→
 412→  const cached = conversationExistenceCache.get(node.conversationId);
 413→  const now = Date.now();
 414→  if (cached && now - cached.checkedAt <= CONVERSATION_EXISTENCE_CACHE_TTL_MS) {
 415→    return cached.exists;
 416→  }
 417→
 418→  if (!node.conversationUrl) {
 419→    conversationExistenceCache.set(node.conversationId, { exists: false, checkedAt: now });
 420→    return false;
 421→  }
 422→
 423→  const controller = new AbortController();
 424→  const timer = setTimeout(() => controller.abort(), CONVERSATION_VERIFY_TIMEOUT_MS);
 425→  try {
 426→    const response = await fetch(node.conversationUrl, {
 427→      method: 'GET',
 428→      redirect: 'follow',
 429→      credentials: 'include',
 430→      signal: controller.signal,
 431→    });
 432→    const responseConversationId = extractConversationIdFromHref(response.url);
 433→    const exists =
 434→      response.ok && !!responseConversationId && node.conversationId === responseConversationId;
 435→    conversationExistenceCache.set(node.conversationId, { exists, checkedAt: now });
 436→    return exists;
 437→  } catch {
 438→    // If verification fails for network/CSP reasons, keep node to avoid destructive false positives.
 439→    return true;
 440→  } finally {
 441→    clearTimeout(timer);
 442→  }
 443→}
 444→
 445→async function pruneDeletedNodesFromGroup(
 446→  groupNodes: ForkNode[],
 447→  sidebarConversationIds: Set<string>,
 448→): Promise<ForkNode[]> {
 449→  const cleaned: ForkNode[] = [];
 450→
 451→  for (const node of groupNodes) {
 452→    const exists = await checkConversationExists(node, sidebarConversationIds);
 453→    if (exists) {
 454→      cleaned.push(node);
 455→      continue;
 456→    }
 457→
 458→    try {
 459→      await ForkNodesService.removeForkNode(node.conversationId, node.turnId, node.forkGroupId);
 460→    } catch (error) {
 461→      if (!isExtensionContextInvalidatedError(error)) {
 462→        console.error('[Fork] Failed to prune deleted fork node:', error);
 463→      }
 464→    }
 465→  }
 466→
 467→  return cleaned;
 468→}
 469→
 470→function clearInjectedForkIndicators(): void {
 471→  document.querySelectorAll(`.${FORK_INDICATOR_GROUP_CLASS}`).forEach((el) => el.remove());
 472→}
 473→
 474→function hasOrDedupForkIndicatorGroup(hostEl: HTMLElement): boolean {
 475→  const groups = Array.from(hostEl.querySelectorAll<HTMLElement>(`.${FORK_INDICATOR_GROUP_CLASS}`));
 476→  if (groups.length === 0) return false;
 477→  if (groups.length > 1) {
 478→    for (let i = 1; i < groups.length; i++) {
 479→      groups[i].remove();
 480→    }
 481→  }
 482→  return true;
 483→}
 484→
 485→/**
 486→ * Extract conversation content up to and including the given user turn index.
 487→ *
 488→ * Step 1: Extract turns 0..N with both user and assistant content when available.
 489→ * Step 2: Remove the last assistant response to let users continue from the last user turn.
 490→ */
 491→function extractConversationUpToTurn(userTurnIndex: number, sourceTurnId: string): string {
 492→  const pairs = collectForkChatPairs();
 493→  if (pairs.length === 0) return '';
 494→
 495→  const sourceIndex = pairs.findIndex(
 496→    (pair) => normalizeTurnId(pair.turnId) === normalizeTurnId(sourceTurnId),
 497→  );
 498→  const targetIndex = sourceIndex >= 0 ? sourceIndex : userTurnIndex;
 499→  const turns: ForkExtractedTurn[] = [];
 500→  for (let i = 0; i <= targetIndex && i < pairs.length; i++) {
 501→    turns.push({
 502→      user: pairs[i].user || '',
 503→      assistant: pairs[i].assistant || '',
 504→    });
 505→  }
 506→
 507→  return buildForkMarkdown(getConversationTitle(), turns, true);
 508→}
