 510→// ============================================================================
 511→// Fork Button Injection
 512→// ============================================================================
 513→
 514→let observer: MutationObserver | null = null;
 515→let observerDebounceTimer: ReturnType<typeof setTimeout> | null = null;
 516→let storageRefreshTimer: ReturnType<typeof setTimeout> | null = null;
 517→let activeConfirm: HTMLElement | null = null;
 518→
