 617→async function executeFork(userEl: HTMLElement, turnIndex: number): Promise<void> {
 618→  const conversationId = extractConversationIdFromUrl();
 619→  if (!conversationId) {
 620→    console.warn('[Fork] No conversation ID found');
 621→    return;
 622→  }
 623→
 624→  const turnId = ensureTurnId(userEl, turnIndex);
 625→  const markdown = extractConversationUpToTurn(turnIndex, turnId);
 626→  if (!markdown.trim()) {
 627→    console.warn('[Fork] No content extracted');
 628→    return;
 629→  }
 630→
 631→  // Open new window IMMEDIATELY to preserve user gesture context.
 632→  // Firefox and Safari block window.open() that follows async operations.
 633→  const newWindow = window.open('https://gemini.google.com/app', '_blank');
 634→  if (!newWindow) {
 635→    console.warn('[Fork] Failed to open new window (popup blocked?)');
 636→    return;
 637→  }
 638→
 639→  // Async work: resolve language and fork group (safe now, window already opened)
 640→  const preferredLanguage = await getPreferredLanguage();
 641→  const markdownWithContext = composeForkInputWithContext(markdown, preferredLanguage);
 642→
 643→  let forkGroupId = generateUniqueId('fork');
 644→  let sourceForkIndex = 0;
 645→  let nextForkIndex = 1;
 646→
 647→  try {
 648→    const conversationNodes = await ForkNodesService.getForConversation(conversationId);
 649→    const candidateGroupIds = Array.from(
 650→      new Set(
 651→        conversationNodes
 652→          .filter((node) => normalizeTurnId(node.turnId) === normalizeTurnId(turnId))
 653→          .map((node) => node.forkGroupId),
 654→      ),
 655→    );
 656→
 657→    const groups: Record<string, ForkNode[]> = {};
 658→    for (const groupId of candidateGroupIds) {
 659→      groups[groupId] = await ForkNodesService.getGroup(groupId);
 660→    }
 661→
 662→    const plan = resolveForkPlan(conversationId, turnId, conversationNodes, groups, () =>
 663→      generateUniqueId('fork'),
 664→    );
 665→
 666→    forkGroupId = plan.forkGroupId;
 667→    sourceForkIndex = plan.sourceForkIndex;
 668→    nextForkIndex = plan.nextForkIndex;
 669→  } catch (error) {
 670→    if (!isExtensionContextInvalidatedError(error)) {
 671→      console.error('[Fork] Failed to resolve fork group, using default:', error);
 672→    }
 673→  }
 674→
 675→  // Store pending fork data in extension storage (cross-tab accessible).
 676→  // sessionStorage is per-tab and its copy semantics with window.open() vary by browser.
 677→  const pendingFork: PendingForkData = {
 678→    sourceConversationId: conversationId,
 679→    sourceTurnId: turnId,
 680→    sourceUrl: window.location.href,
 681→    sourceTitle: getConversationTitle(),
 682→    forkGroupId,
 683→    sourceForkIndex,
 684→    nextForkIndex,
 685→    markdown: markdownWithContext,
 686→    createdAt: Date.now(),
 687→  };
 688→
 689→  try {
 690→    await browser.storage.local.set({ [PENDING_FORK_KEY]: pendingFork });
 691→  } catch (e) {
 692→    console.error('[Fork] Failed to save pending fork:', e);
 693→  }
 694→}
