 696→// ============================================================================
 697→// Pending Fork Handling (New Conversation)
 698→// ============================================================================
 699→
 700→interface PendingForkData {
 701→  sourceConversationId: string;
 702→  sourceTurnId: string;
 703→  sourceUrl: string;
 704→  sourceTitle: string;
 705→  forkGroupId: string;
 706→  sourceForkIndex: number;
 707→  nextForkIndex: number;
 708→  markdown: string;
 709→  createdAt?: number;
 710→}
 711→
 712→const PENDING_FORK_STALE_MS = 60000; // Discard pending fork data older than 60s
 713→
 714→async function readPendingFork(): Promise<PendingForkData | null> {
 715→  try {
 716→    const result = await browser.storage.local.get(PENDING_FORK_KEY);
 717→    const parsed = result[PENDING_FORK_KEY] as Partial<PendingForkData> | undefined;
 718→    if (!parsed) return null;
 719→
 720→    // Discard stale data (e.g. from a previous failed fork)
 721→    if (parsed.createdAt && Date.now() - parsed.createdAt > PENDING_FORK_STALE_MS) {
 722→      await browser.storage.local.remove(PENDING_FORK_KEY);
 723→      return null;
 724→    }
 725→
 726→    const pendingFork: PendingForkData = {
 727→      sourceConversationId: parsed.sourceConversationId || '',
 728→      sourceTurnId: parsed.sourceTurnId || '',
 729→      sourceUrl: parsed.sourceUrl || '',
 730→      sourceTitle: parsed.sourceTitle || '',
 731→      forkGroupId: parsed.forkGroupId || '',
 732→      sourceForkIndex: Number.isFinite(parsed.sourceForkIndex) ? parsed.sourceForkIndex! : 0,
 733→      nextForkIndex: Number.isFinite(parsed.nextForkIndex) ? parsed.nextForkIndex! : 1,
 734→      markdown: parsed.markdown || '',
 735→      createdAt: parsed.createdAt,
 736→    };
 737→
 738→    if (
 739→      !pendingFork.sourceConversationId ||
 740→      !pendingFork.sourceTurnId ||
 741→      !pendingFork.forkGroupId ||
 742→      !pendingFork.markdown.trim()
 743→    ) {
 744→      await browser.storage.local.remove(PENDING_FORK_KEY);
 745→      return null;
 746→    }
 747→
 748→    return pendingFork;
 749→  } catch {
 750→    return null;
 751→  }
 752→}
 753→
 754→function checkAndHandlePendingFork(): void {
 755→  // Only handle on a new conversation page (no conversation ID yet)
 756→  const currentConvId = extractConversationIdFromUrl();
 757→  if (currentConvId) return;
 758→
 759→  // Clean up legacy sessionStorage data (from versions before this fix)
 760→  try {
 761→    sessionStorage.removeItem(PENDING_FORK_KEY);
 762→  } catch {
 763→    // Ignore
 764→  }
 765→
 766→  void handlePendingForkFromStorage();
 767→}
 768→
 769→async function handlePendingForkFromStorage(): Promise<void> {
 770→  // The opener tab writes to storage.local after async work, which may take a moment.
 771→  // Try immediately, then retry once after a short delay.
 772→  let pendingFork = await readPendingFork();
 773→  if (!pendingFork) {
 774→    await new Promise((r) => setTimeout(r, 2000));
 775→    pendingFork = await readPendingFork();
 776→  }
 777→  if (!pendingFork) return;
 778→
 779→  // Clear immediately so other tabs don't pick it up
 780→  try {
 781→    await browser.storage.local.remove(PENDING_FORK_KEY);
 782→  } catch {
 783→    // Ignore
 784→  }
 785→
 786→  // Re-check: still on a new conversation page?
 787→  if (extractConversationIdFromUrl()) return;
 788→
 789→  // Wait for the input field to be available
 790→  const input = await waitForElement('rich-textarea [contenteditable="true"]', 10000);
 791→  if (!input) {
 792→    console.warn('[Fork] Input field not found');
 793→    return;
 794→  }
 795→
 796→  // Paste the markdown content
 797→  input.focus();
 798→  try {
 799→    document.execCommand('insertText', false, pendingFork.markdown);
 800→  } catch {
 801→    // Fallback: set textContent
 802→    input.textContent = pendingFork.markdown;
 803→    input.dispatchEvent(new Event('input', { bubbles: true }));
 804→  }
 805→
 806→  // Watch for URL change (conversation created after submission)
 807→  watchForNewConversation(pendingFork);
 808→}
 809→
 810→function waitForElement(selector: string, timeoutMs: number): Promise<HTMLElement | null> {
 811→  return new Promise((resolve) => {
 812→    const existing = document.querySelector<HTMLElement>(selector);
 813→    if (existing && existing.getBoundingClientRect().height > 0) {
 814→      resolve(existing);
 815→      return;
 816→    }
 817→
 818→    const deadline = Date.now() + timeoutMs;
 819→    const check = () => {
 820→      const el = document.querySelector<HTMLElement>(selector);
 821→      if (el && el.getBoundingClientRect().height > 0) {
 822→        resolve(el);
 823→        return;
 824→      }
 825→      if (Date.now() > deadline) {
 826→        resolve(null);
 827→        return;
 828→      }
 829→      requestAnimationFrame(check);
 830→    };
 831→    requestAnimationFrame(check);
 832→  });
 833→}
 834→
 835→function watchForNewConversation(pendingFork: PendingForkData): void {
 836→  let lastUrl = window.location.href;
 837→
 838→  const checkUrl = async () => {
 839→    const currentUrl = window.location.href;
 840→    if (currentUrl === lastUrl) return;
 841→    lastUrl = currentUrl;
 842→
 843→    const newConvId = extractConversationIdFromUrl();
 844→    if (!newConvId) return;
 845→
 846→    // New conversation created! Create fork nodes for both sides
 847→    urlObserver.disconnect();
 848→
 849→    try {
 850→      // Create fork node for the SOURCE conversation (original, index 0)
 851→      const sourceNode: ForkNode = {
 852→        turnId: pendingFork.sourceTurnId,
 853→        conversationId: pendingFork.sourceConversationId,
 854→        conversationUrl: pendingFork.sourceUrl,
 855→        conversationTitle: pendingFork.sourceTitle,
 856→        forkGroupId: pendingFork.forkGroupId,
 857→        forkIndex: pendingFork.sourceForkIndex,
 858→        createdAt: Date.now(),
 859→      };
 860→      await ForkNodesService.addForkNode(sourceNode);
 861→
 862→      // Create fork node for the NEW conversation (fork)
 863→      // Use the first user turn ID in the new conversation
 864→      const newNode: ForkNode = {
 865→        turnId: 'u-0', // First user turn in new conversation
 866→        conversationId: newConvId,
 867→        conversationUrl: currentUrl,
 868→        conversationTitle: getConversationTitle(),
 869→        forkGroupId: pendingFork.forkGroupId,
 870→        forkIndex: pendingFork.nextForkIndex,
 871→        createdAt: Date.now(),
 872→      };
 873→      await ForkNodesService.addForkNode(newNode);
 874→
 875→      // Inject fork indicators in the new conversation
 876→      setTimeout(() => injectForkIndicators(), 1000);
 877→    } catch (error) {
 878→      if (!isExtensionContextInvalidatedError(error)) {
 879→        console.error('[Fork] Failed to create fork nodes:', error);
 880→      }
 881→    }
 882→  };
 883→
 884→  // Use a MutationObserver on the URL (via popstate + polling)
 885→  const urlObserver = new MutationObserver(() => void checkUrl());
 886→  urlObserver.observe(document, { subtree: true, childList: true });
 887→
 888→  // Also listen to popstate and hashchange
 889→  const onUrlChange = () => void checkUrl();
 890→  window.addEventListener('popstate', onUrlChange);
 891→  window.addEventListener('hashchange', onUrlChange);
 892→
 893→  // Poll as fallback (SPA navigation may not trigger popstate)
 894→  const pollInterval = setInterval(() => {
 895→    void checkUrl();
 896→  }, 500);
 897→
 898→  // Cleanup after 60 seconds
 899→  setTimeout(() => {
 900→    urlObserver.disconnect();
 901→    window.removeEventListener('popstate', onUrlChange);
 902→    window.removeEventListener('hashchange', onUrlChange);
 903→    clearInterval(pollInterval);
 904→  }, 60000);
 905→}
