 907→// ============================================================================
 908→// Fork Indicator UI
 909→// ============================================================================
 910→
 911→async function injectForkIndicators(): Promise<void> {
 912→  const conversationId = extractConversationIdFromUrl();
 913→  if (!conversationId) return;
 914→
 915→  let forkNodes: ForkNode[];
 916→  try {
 917→    forkNodes = await ForkNodesService.getForConversation(conversationId);
 918→  } catch (error) {
 919→    if (!isExtensionContextInvalidatedError(error)) {
 920→      console.error('[Fork] Failed to get fork nodes:', error);
 921→    }
 922→    return;
 923→  }
 924→
 925→  if (forkNodes.length === 0) return;
 926→
 927→  // Build a map of normalized turnId -> forkGroupIds
 928→  const turnForkMap = new Map<string, Set<string>>();
 929→  for (const node of forkNodes) {
 930→    const normalizedTurnId = normalizeTurnId(node.turnId);
 931→    if (!turnForkMap.has(normalizedTurnId)) {
 932→      turnForkMap.set(normalizedTurnId, new Set<string>());
 933→    }
 934→    turnForkMap.get(normalizedTurnId)?.add(node.forkGroupId);
 935→  }
 936→
 937→  const pairs = collectForkChatPairs();
 938→  const sidebarConversationIds = collectSidebarConversationIds();
 939→  if (conversationId) sidebarConversationIds.add(conversationId);
 940→
 941→  for (let index = 0; index < pairs.length; index++) {
 942→    const userEl = pairs[index].userElement;
 943→    const turnId = normalizeTurnId(ensureTurnId(userEl, index));
 944→    const hostEl = resolveUserMessageHost(userEl);
 945→    const forkGroupIds = turnForkMap.get(turnId);
 946→    if (!forkGroupIds || forkGroupIds.size === 0) continue;
 947→
 948→    if (hasOrDedupForkIndicatorGroup(hostEl)) continue;
 949→
 950→    const groupNodesList: ForkNode[][] = [];
 951→    for (const forkGroupId of forkGroupIds) {
 952→      try {
 953→        const groupNodes = await ForkNodesService.getGroup(forkGroupId);
 954→        if (groupNodes.length === 0) continue;
 955→        const cleanedGroupNodes = await pruneDeletedNodesFromGroup(
 956→          groupNodes,
 957→          sidebarConversationIds,
 958→        );
 959→        if (cleanedGroupNodes.length > 0) groupNodesList.push(cleanedGroupNodes);
 960→      } catch {
 961→        // Ignore single group failure and continue rendering available groups.
 962→      }
 963→    }
 964→    if (groupNodesList.length === 0) continue;
 965→
 966→    const displayNodes = buildBranchDisplayNodes(groupNodesList);
 967→    if (displayNodes.length < 2) continue;
 968→
 969→    // Re-check after async group loading to avoid duplicate render in concurrent injections.
 970→    if (hasOrDedupForkIndicatorGroup(hostEl)) continue;
 971→
 972→    const group = document.createElement('div');
 973→    group.className = FORK_INDICATOR_GROUP_CLASS;
 974→
 975→    for (let displayIndex = 0; displayIndex < displayNodes.length; displayIndex++) {
 976→      const node = displayNodes[displayIndex];
 977→      const branchNumber = displayIndex + 1;
 978→      const isCurrent = node.conversationId === conversationId;
 979→      const item = document.createElement('div');
 980→      item.className = FORK_INDICATOR_ITEM_CLASS;
 981→
 982→      const indicator = document.createElement('button');
 983→      indicator.className = `${FORK_INDICATOR_CLASS}${isCurrent ? ' gv-current' : ''}`;
 984→      indicator.type = 'button';
 985→      indicator.textContent = String(branchNumber);
 986→      indicator.title = `${getTranslationSync('forkBranch')} ${branchNumber}${
 987→        isCurrent ? ` - ${getTranslationSync('forkCurrent')}` : ''
 988→      }`;
 989→
 990→      if (isCurrent) {
 991→        indicator.setAttribute('aria-current', 'true');
 992→        indicator.disabled = true;
 993→      } else {
 994→        indicator.addEventListener('click', (e) => {
 995→          e.stopPropagation();
 996→          e.preventDefault();
 997→          navigateToForkConversation(node);
 998→        });
 999→      }
1000→      item.appendChild(indicator);
1001→
1002→      const deleteBtn = document.createElement('button');
1003→      deleteBtn.className = FORK_INDICATOR_DELETE_CLASS;
1004→      deleteBtn.type = 'button';
1005→      deleteBtn.textContent = '×';
1006→      deleteBtn.title = getTranslationSync('forkDeleteData');
1007→      deleteBtn.setAttribute('aria-label', getTranslationSync('forkDeleteData'));
1008→      deleteBtn.addEventListener('click', async (e) => {
1009→        e.stopPropagation();
1010→        e.preventDefault();
1011→        const confirmed = window.confirm(getTranslationSync('forkDeleteDataConfirm'));
1012→        if (!confirmed) return;
1013→
1014→        deleteBtn.disabled = true;
1015→        try {
1016→          await ForkNodesService.removeForkNode(node.conversationId, node.turnId, node.forkGroupId);
1017→        } catch (error) {
1018→          if (!isExtensionContextInvalidatedError(error)) {
1019→            console.error('[Fork] Failed to delete fork branch data:', error);
1020→          }
1021→        } finally {
1022→          clearInjectedForkIndicators();
1023→          void injectForkIndicators();
1024→        }
1025→      });
1026→      item.appendChild(deleteBtn);
1027→      group.appendChild(item);
1028→    }
1029→
1030→    hostEl.style.position = hostEl.style.position || 'relative';
1031→    hostEl.appendChild(group);
1032→  }
1033→}
