1065→// ============================================================================
1066→// Module Entry Point
1067→// ============================================================================
1068→
1069→export function startFork(): () => void {
1070→  injectStyles();
1071→
1072→  // Check for pending fork data (new conversation paste)
1073→  checkAndHandlePendingFork();
1074→
1075→  // Inject fork buttons and indicators
1076→  const setup = () => {
1077→    injectForkButtons();
1078→    void injectForkIndicators();
1079→  };
1080→
1081→  // Initial injection with delay to let DOM settle
1082→  setTimeout(setup, 1000);
1083→
1084→  // MutationObserver for dynamically loaded messages
1085→  observer = new MutationObserver(() => {
1086→    if (observerDebounceTimer) clearTimeout(observerDebounceTimer);
1087→    observerDebounceTimer = setTimeout(() => {
1088→      injectForkButtons();
1089→      void injectForkIndicators();
1090→    }, OBSERVER_DEBOUNCE_MS);
1091→  });
1092→
1093→  observer.observe(document.body, {
1094→    childList: true,
1095→    subtree: true,
1096→  });
1097→
1098→  // Dismiss confirm dialog on click outside
1099→  document.addEventListener('click', onDocumentClick);
1100→
1101→  // Language change listener
1102→  const onStorageChanged = (
1103→    changes: Record<string, browser.Storage.StorageChange>,
1104→    areaName: string,
1105→  ) => {
1106→    if ((areaName === 'sync' || areaName === 'local') && changes[StorageKeys.LANGUAGE]) {
1107→      updateForkButtonTexts();
1108→    }
1109→    if (areaName === 'local' && changes[StorageKeys.FORK_NODES]) {
1110→      scheduleForkIndicatorRefresh();
1111→    }
1112→  };
1113→  browser.storage.onChanged.addListener(onStorageChanged);
1114→
1115→  // Cleanup function
1116→  return () => {
1117→    if (observer) {
1118→      observer.disconnect();
1119→      observer = null;
1120→    }
1121→    if (observerDebounceTimer) {
1122→      clearTimeout(observerDebounceTimer);
1123→      observerDebounceTimer = null;
1124→    }
1125→    if (storageRefreshTimer) {
1126→      clearTimeout(storageRefreshTimer);
1127→      storageRefreshTimer = null;
1128→    }
1129→    dismissConfirm();
1130→    document.removeEventListener('click', onDocumentClick);
