  if (copyBtn) {
    const parent = copyBtn.parentElement;
    const grandParent = parent?.parentElement;

    // Get computed styles of copy button and its parent
    const copyStyle = window.getComputedStyle(copyBtn);
    const parentStyle = parent ? window.getComputedStyle(parent) : null;
    const grandParentStyle = grandParent ? window.getComputedStyle(grandParent) : null;

    result.push({
      userQueryIndex: i,
      copyButton: {
        tagName: copyBtn.tagName,
        className: copyBtn.className,
        width: copyStyle.width,
        height: copyStyle.height,
        display: copyStyle.display,
        rect: copyBtn.getBoundingClientRect(),
      },
      parent: parent ? {
        tagName: parent.tagName,
        className: parent.className,
        display: parentStyle.display,
        alignItems: parentStyle.alignItems,
        justifyContent: parentStyle.justifyContent,
        flexDirection: parentStyle.flexDirection,
        position: parentStyle.position,
        height: parentStyle.height,
        width: parentStyle.width,
        rect: parent.getBoundingClientRect(),
        childCount: parent.children.length,
        children: Array.from(parent.children).map(c => ({
          tagName: c.tagName,
          className: c.className.substring(0, 80),
          rect: c.getBoundingClientRect(),
        }))
      } : null,
      grandParent: grandParent ? {
        tagName: grandParent.tagName,
        className: grandParent.className?.substring(0, 80),
        display: grandParentStyle.display,
        alignItems: grandParentStyle.alignItems,
        position: grandParentStyle.position,
        height: grandParentStyle.height,
        rect: grandParent.getBoundingClientRect(),
      } : null,
    });
  }

  // Also check the bubble container
  const bubble = uq.querySelector('.user-query-bubble-with-background');
  if (bubble) {
    const bubbleStyle = window.getComputedStyle(bubble);
