// Check the current fork button style to verify the change would work
// The extension needs a rebuild, so let me just verify the math
const uq = document.querySelector('user-query, .user-query-container');
const copyBtn = uq.querySelector('button[aria-label="复制提示"]');
const forkBtn = uq.querySelector('.gv-fork-btn');

const copyRect = copyBtn?.getBoundingClientRect();
const forkRect = forkBtn?.getBoundingClientRect();

// After fix: fork top should be at copyRect.top + 9 = 94 + 9 = 103
// Fork center: 103 + 11 = 114
// Copy center: 94 + 20 = 114 ✓
JSON.stringify({
  copyCenter: copyRect ? copyRect.top + copyRect.height / 2 : null,
  forkCurrentCenter: forkRect ? forkRect.top + forkRect.height / 2 : null,
  forkFixedCenter: copyRect && forkRect ? copyRect.top + 9 + forkRect.height / 2 : null,
  aligned: copyRect && forkRect ? 
    Math.abs((copyRect.top + copyRect.height / 2) - (copyRect.top + 9 + forkRect.height / 2)) < 1 : null
});

